  ('elementary-0a2fc18c-moex-00393', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-113-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '在沒有貿易部門的簡單凱因斯模型中，邊際消費傾向為 0.80，當政府消費支出增加 100 元時，均衡所得 最多將增加：', '["80元", "100元", "135元", "500元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:15+00:00", "source_pdf_sha1": "eec406787878", "answer_pdf_sha1": "1308ad5b4fe4", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "511", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00394', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-113-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '某一國家其總合供給與需求函數分別為Ys＝60P＋400與Yd＝3100－30P。若該國充分就業的產出水準為 2500，則根據凱因斯學派的論點，下列敘述何者正確？', '["該國目前的勞動供給量大於勞動需求量且名目工資無法向下調整", "該國目前的勞動供給量小於勞動需求量且名目工資無法向下調整", "該國目前的勞動供給量等於勞動需求量且名目工資無法向下調整", "該國目前的勞動供給量等於勞動需求量且名目工資可以自由調整"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:15+00:00", "source_pdf_sha1": "eec406787878", "answer_pdf_sha1": "1308ad5b4fe4", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "511", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00395', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-113-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '給定其他條件不變下，下列何者會使總合需求線右移？①政府取消投資抵減優惠  ②政府減稅使人們稅', '["人們關注退休金制度改革議題，減少現在消費以增加儲蓄", "人工智慧技術發展，使廠商 增加相關設備之採購", "僅", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:15+00:00", "source_pdf_sha1": "eec406787878", "answer_pdf_sha1": "1308ad5b4fe4", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "511", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 47, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00396', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-113-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '依據流動性偏好理論，有關實質貨幣餘額需求（m）與利率的關係，下列敘述何者正確？', '["m與實質利率成正相關", "m與實質利率成負相關", "m與名目利率成正相關", "m與名目利率成負相關"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:15+00:00", "source_pdf_sha1": "eec406787878", "answer_pdf_sha1": "1308ad5b4fe4", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "511", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00397', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-113-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '在其他條件不變下，下列何者會使貨幣供給減少？', '["中央銀行賣出債券", "銀行的超額準備減少", "人們持有通貨的意願下降", "銀行的放款增加"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:15+00:00", "source_pdf_sha1": "eec406787878", "answer_pdf_sha1": "1308ad5b4fe4", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "511", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00398', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-113-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '根據政府預算限制式的內容，下列何者不是政府的收入來源？', '["外匯存底", "印製貨幣", "課徵租稅", "發行公債"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:15+00:00", "source_pdf_sha1": "eec406787878", "answer_pdf_sha1": "1308ad5b4fe4", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "511", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00399', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-b3f42868', 'sub-elementary-0a2fc18c-01', NULL, 'single_choice', '一國面對景氣衰退時，政府往往會透過某些措施的採行，刺激景氣復甦，帶動經濟成長。下列何者無法 達成刺激景氣復甦的目標？', '["增加公共投資", "降低重貼現率", "獎勵民間投資", "取消補貼政策"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:15+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00400', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-b3f42868', 'sub-elementary-0a2fc18c-01', NULL, 'single_choice', '若世界僅由甲、乙兩國組成，且甲國生產所有商品的效率皆比乙國的水準高。若以機會成本的觀點而言， 下列有關甲、乙兩國生產及貿易的敘述，何者正確？', '["甲國生產所有商品均具絕對利益", "乙國向甲國進口所有產品最有利", "甲國生產所有商品的機會成本低於乙國", "若兩國進行分工，甲、乙兩國的生產可能線會內縮"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:15+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00401', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-b3f42868', 'sub-elementary-0a2fc18c-01', NULL, 'single_choice', '大學剛畢業的小湘有三個工作機會與繼續升學的道路可選擇，一是月薪2萬5千元的家教老師；另一是 月薪2萬8千元的房屋仲介；以及月薪3萬元的法務助理；若選擇不就業，繼續進入研究所碩士班就讀， 學雜費兩年共需20萬元。依上述資料判斷，在不考慮其他條件的情況下，針對小湘大學畢業後兩年間做 選擇的機會成本之敘述，下列何者正確？', '["若當家教老師，機會成本為67萬2千元", "若選擇當房屋仲介，外顯成本為72萬元", "若選擇就學，外顯成本為72萬元", "若選擇就學，機會成本為92萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:15+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00402', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-b3f42868', 'sub-elementary-0a2fc18c-01', NULL, 'single_choice', '從塑化劑事件到毒澱粉，食安危機連環爆，連許多老店與大公司的知名產品都因使用有害人體健康的原 料，使消費者人人自危，深怕吃下肚的是黑心商品。許多產品銷售成績一落千丈，對加工食品業的業績 有負面影響。上述事件使消費者對加工食品需求的影響，下列何者正確？', '["預期加工食品價格會下跌，導致其需求曲線左移", "消費者對加工食品的偏好降低，導致其需求曲線左移", "加工食品的互補品價格下跌，導致加工食品的需求曲線右移", "天然食材製品的價格上漲，導致加工食品的需求曲線右移"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:15+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL)
